// Formatting utilities for session metrics display

import dayjs from 'dayjs'
import relativeTime from 'dayjs/plugin/relativeTime'

dayjs.extend(relativeTime)

export const formatMs = (ms: number): string => {
  if (ms < 1) return '<1ms'
  if (ms < 1000) return `${Math.round(ms)}ms`
  return `${(ms / 1000).toFixed(2)}s`
}

export const formatDuration = (ms: number | null): string => {
  if (ms == null) return '—'
  const seconds = Math.floor(ms / 1000)
  const minutes = Math.floor(seconds / 60)
  const hours = Math.floor(minutes / 60)
  if (hours > 0) return `${hours}h ${minutes % 60}m ${seconds % 60}s`
  if (minutes > 0) return `${minutes}m ${seconds % 60}s`
  return `${seconds}s`
}

export const formatDate = (iso: string | null): string => {
  if (!iso) return '—'
  return dayjs(iso).format('MMM D, YYYY h:mm A')
}

/** Compact token-count rendering — millions and thousands rounded for at-
 *  a-glance reading. 1234 → "1.2K", 1_234_567 → "1.2M". Zero renders "0"
 *  (callers decide whether to em-dash when no data). */
export const formatTokens = (n: number): string => {
  if (!Number.isFinite(n) || n <= 0) return '0'
  if (n >= 1_000_000) {
    const m = n / 1_000_000
    return `${m >= 10 ? m.toFixed(0) : m.toFixed(1)}M`
  }
  if (n >= 1_000) {
    const k = n / 1000
    return `${k >= 10 ? k.toFixed(0) : k.toFixed(1)}K`
  }
  return n.toLocaleString('en-US')
}

/** Compact USD rendering. <$0.01 → "<$0.01" so tiny but non-zero costs
 *  don't get rounded to $0.00 and look like "we couldn't price you". */
export const formatCost = (usd: number | null | undefined): string => {
  if (usd == null || !Number.isFinite(usd)) return '—'
  if (usd === 0) return '$0.00'
  if (usd > 0 && usd < 0.01) return '<$0.01'
  if (usd >= 1000) return `$${Math.round(usd).toLocaleString('en-US')}`
  return `$${usd.toFixed(2)}`
}

export const computeAvg = (values: number[]) => {
  if (!values.length) return 0
  return Math.round(values.reduce((a, b) => a + b, 0) / values.length)
}

export const computePercentile = (values: number[], p: number) => {
  if (!values.length) return 0
  const sorted = [...values].sort((a, b) => a - b)
  const idx = Math.min(Math.floor(sorted.length * p), sorted.length - 1)
  return sorted[idx]
}

// Stringifies a tool-call argument or a tool-result output for display.
// Tries each format in order and returns the first one that parses:
//   1. Strict JSON — the right format. Tools that return native dicts via the
//      LiveKit Python SDK serialize this way.
//   2. Python repr — when a tool ran `str(dict)` instead of `json.dumps(dict)`,
//      we get single quotes, capitalized True/False/None. This is a *best
//      effort* recovery; it breaks if any string value contains an apostrophe
//      (e.g. "O'Brien") because the heuristic flips every `'` to `"`. The
//      proper fix is producer-side — make tools return JSON-shaped output.
//   3. Raw string — plain text outputs (e.g. "shipped") render as-is so they
//      aren't wrapped in extra quotes.
// Non-strings (already-an-object/array) are JSON-stringified directly.
export function formatToolValue(value: unknown): string {
  if (value == null) return ''
  if (typeof value !== 'string') return JSON.stringify(value, null, 2)
  try {
    return JSON.stringify(JSON.parse(value), null, 2)
  } catch {
    // Python-repr fallback. Only attempt for strings that look like a dict /
    // list — don't munge plain text containing the word `True`.
    const trimmed = value.trim()
    if (trimmed.startsWith('{') || trimmed.startsWith('[')) {
      try {
        const jsonish = value
          .replace(/(?<!\\)'/g, '"')
          .replace(/\bTrue\b/g, 'true')
          .replace(/\bFalse\b/g, 'false')
          .replace(/\bNone\b/g, 'null')
        return JSON.stringify(JSON.parse(jsonish), null, 2)
      } catch {
        // fall through to raw string
      }
    }
    return value
  }
}

import type { SessionEvent } from '@/lib/observability-types'

export function getEventCreatedAt(event: SessionEvent): number | null {
  const value = (event as unknown as { created_at?: unknown }).created_at
  if (typeof value === 'number' && Number.isFinite(value)) return value
  if (typeof value === 'string') {
    const parsed = Date.parse(value)
    return Number.isFinite(parsed) ? parsed / 1000 : null
  }
  return null
}

export function sortEventsByCreatedAt(
  events: readonly SessionEvent[] | null | undefined,
): SessionEvent[] | null {
  if (!events) return null
  return events
    .map((event, index) => ({ event, index }))
    .sort((a, b) => {
      const at = getEventCreatedAt(a.event)
      const bt = getEventCreatedAt(b.event)
      if (at == null && bt == null) return a.index - b.index
      if (at == null) return 1
      if (bt == null) return -1
      return at - bt || a.index - b.index
    })
    .map(({ event }) => event)
}

export function getEventTimeRange(
  events: readonly SessionEvent[] | null | undefined,
): { start: number; end: number } | null {
  if (!events) return null
  const eventTimes = events
    .map(getEventCreatedAt)
    .filter((value): value is number => value != null)
  if (eventTimes.length === 0) return null
  return {
    start: eventTimes[0],
    end: eventTimes[eventTimes.length - 1],
  }
}

import type {
  AgentRow,
  AgentSessionRow,
  AgentStats,
  AgentStatsRange,
  AgentsFilters,
  ConversationEvalSummary,
  EvalCaseRow,
  EvalRunDetail,
  EvalRunRow,
  EvalsFilters,
  PlivoListResponse,
  SessionsFilters,
} from '@/lib/observability-types'

export function createObservabilityApi(baseUrl: string) {
  async function fetchJson<T>(path: string, init?: RequestInit): Promise<T> {
    const res = await fetch(`${baseUrl}${path}`, init)
    if (!res.ok) throw new Error(`API error: ${res.status} ${res.statusText}`)
    return res.json()
  }

  return {
    listSessions: (limit = 20, offset = 0, filters?: SessionsFilters) => {
      const params = new URLSearchParams({ limit: String(limit), offset: String(offset) })
      if (filters?.accountId) params.set('account_id', filters.accountId)
      if (filters?.agentId) params.set('agent_id', filters.agentId)
      if (filters?.agentName) params.set('agent_name', filters.agentName)
      if (filters?.startedFrom) params.set('started_from', filters.startedFrom)
      if (filters?.startedTo) params.set('started_to', filters.startedTo)
      if (filters?.transport && filters.transport.length) {
        params.set('transport', filters.transport.join(','))
      }
      return fetchJson<PlivoListResponse<AgentSessionRow>>(`/sessions?${params}`)
    },

    listAgents: (limit = 50, offset = 0, filters?: AgentsFilters) => {
      const params = new URLSearchParams({
        limit: String(limit),
        offset: String(offset),
      })
      if (filters?.accountId) params.set('account_id', filters.accountId)
      if (filters?.agentId) params.set('agent_id', filters.agentId)
      if (filters?.agentName) params.set('agent_name', filters.agentName)
      return fetchJson<PlivoListResponse<AgentRow>>(`/agents?${params}`)
    },

    getAgent: (agentId: string, accountId?: string | null) => {
      const params = new URLSearchParams()
      if (accountId) params.set('account_id', accountId)
      const qs = params.toString()
      return fetchJson<AgentRow>(`/agents/${encodeURIComponent(agentId)}${qs ? `?${qs}` : ''}`)
    },

    getAgentStats: (
      agentId: string,
      range: AgentStatsRange = '24h',
      accountId?: string | null,
    ) => {
      const params = new URLSearchParams({ range })
      if (accountId) params.set('account_id', accountId)
      return fetchJson<AgentStats>(
        `/agents/${encodeURIComponent(agentId)}/stats?${params}`,
      )
    },

    listConversationEvals: (
      agentId: string,
      limit = 50,
      offset = 0,
      filters?: {
        accountId?: string | null
        sessionId?: string | null
        failedOnly?: boolean
      },
    ) => {
      const params = new URLSearchParams({ limit: String(limit), offset: String(offset) })
      if (filters?.accountId) params.set('account_id', filters.accountId)
      if (filters?.sessionId) params.set('session_id', filters.sessionId)
      if (filters?.failedOnly) params.set('failed', 'true')
      return fetchJson<PlivoListResponse<ConversationEvalSummary>>(
        `/agents/${encodeURIComponent(agentId)}/conversation-evals?${params}`,
      )
    },

    getSession: (id: string) =>
      fetchJson<AgentSessionRow>(`/sessions/${id}`),

    deleteSessions: (sessionIds: string[]) =>
      fetchJson<{ api_id: string; deleted: number }>(`/sessions`, {
        method: 'DELETE',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ session_ids: sessionIds }),
      }),

    listEvalRuns: (limit = 20, offset = 0, filters?: EvalsFilters) => {
      const params = new URLSearchParams({ limit: String(limit), offset: String(offset) })
      if (filters?.agentId) params.set('agent_id', filters.agentId)
      if (filters?.framework && filters.framework.length) {
        params.set('framework', filters.framework.join(','))
      }
      if (filters?.testingFramework && filters.testingFramework.length) {
        params.set('testing_framework', filters.testingFramework.join(','))
      }
      if (filters?.accountId) params.set('account_id', filters.accountId)
      if (filters?.startedFrom) params.set('started_from', filters.startedFrom)
      if (filters?.startedTo) params.set('started_to', filters.startedTo)
      return fetchJson<PlivoListResponse<EvalRunRow>>(`/evals?${params}`)
    },

    getEvalRun: (runId: string) =>
      fetchJson<EvalRunDetail>(`/evals/${runId}`),

    getEvalCase: (runId: string, caseId: string) =>
      fetchJson<EvalCaseRow & { api_id?: string }>(`/evals/${runId}/cases/${caseId}`),

    deleteEvalRuns: (runIds: string[]) =>
      fetchJson<{ api_id: string; deleted: number }>(`/evals`, {
        method: 'DELETE',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ run_ids: runIds }),
      }),

    deleteEvalCases: (runId: string, caseIds: string[]) =>
      fetchJson<{ api_id: string; deleted: number }>(`/evals/${runId}/cases`, {
        method: 'DELETE',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ case_ids: caseIds }),
      }),
  }
}

export type ObservabilityApi = ReturnType<typeof createObservabilityApi>

import {
  createContext,
  useContext,
  useEffect,
  useMemo,
  useState,
  type ReactNode,
} from 'react'
import { createObservabilityApi, type ObservabilityApi } from '@/lib/observability-api'
import type { AgentSessionRow } from '@/lib/observability-types'

interface ObservabilityContextValue {
  api: ObservabilityApi
  session: AgentSessionRow | null
  sessionLoading: boolean
  sessionError: string | null
  highlightedTurn: number | null
  setHighlightedTurn: (turn: number | null) => void
}

const ObservabilityContext = createContext<ObservabilityContextValue | null>(null)

export function AgentObservabilityProvider({
  baseUrl,
  sessionId,
  children,
}: {
  baseUrl: string
  sessionId?: string
  children: ReactNode
}) {
  const api = useMemo(() => createObservabilityApi(baseUrl), [baseUrl])
  const [session, setSession] = useState<AgentSessionRow | null>(null)
  const [sessionLoading, setSessionLoading] = useState(!!sessionId)
  const [sessionError, setSessionError] = useState<string | null>(null)
  const [highlightedTurn, setHighlightedTurn] = useState<number | null>(null)

  useEffect(() => {
    if (!sessionId) {
      setSession(null)
      setSessionLoading(false)
      return
    }
    setSessionLoading(true)
    setSessionError(null)
    api
      .getSession(sessionId)
      .then(setSession)
      .catch((e) => setSessionError(e.message))
      .finally(() => setSessionLoading(false))
  }, [api, sessionId])

  const value = useMemo<ObservabilityContextValue>(
    () => ({
      api,
      session,
      sessionLoading,
      sessionError,
      highlightedTurn,
      setHighlightedTurn,
    }),
    [api, session, sessionLoading, sessionError, highlightedTurn],
  )

  return (
    <ObservabilityContext.Provider value={value}>
      {children}
    </ObservabilityContext.Provider>
  )
}

export function useObservabilityContext() {
  const ctx = useContext(ObservabilityContext)
  if (!ctx) {
    throw new Error('useObservabilityContext must be used within AgentObservabilityProvider')
  }
  return ctx
}

import { useEffect, useMemo, useState } from 'react'
import { useObservabilityContext } from '@/lib/observability-provider'
import { sortEventsByCreatedAt } from '@/lib/observability-events'
import type {
  AgentRow,
  AgentSessionRow,
  AgentStats,
  AgentStatsRange,
  AgentsFilters,
  ChatItem,
  ConversationEvalSummary,
  EvalCaseRow,
  EvalRunDetail,
  EvalRunRow,
  EvalsFilters,
  MetricsSummary,
  PlivoMeta,
  SessionExternalEvaluation,
  SessionEvent,
  SessionMetrics,
  SessionOutcome,
  SessionTag,
  SessionsFilters,
  TurnRecord,
} from '@/lib/observability-types'

// ---------------------------------------------------------------------------
// useSessions — fetches paginated session list
// ---------------------------------------------------------------------------

export function useSessions(
  limit = 20,
  offset = 0,
  filters?: SessionsFilters,
) {
  const { api } = useObservabilityContext()
  const [sessions, setSessions] = useState<AgentSessionRow[]>([])
  const [meta, setMeta] = useState<PlivoMeta>({
    limit,
    offset,
    total_count: 0,
    next: null,
    previous: null,
  })
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)
  // Bumping this re-runs the fetch effect — used by callers to refresh
  // after a mutation like bulk delete.
  const [refetchTick, setRefetchTick] = useState(0)
  const refetch = useMemo(() => () => setRefetchTick((v) => v + 1), [])

  const accountId = filters?.accountId
  const agentId = filters?.agentId
  const agentName = filters?.agentName
  const startedFrom = filters?.startedFrom
  const startedTo = filters?.startedTo
  const transport = filters?.transport
  const transportKey = (transport ?? []).slice().sort().join(',')

  useEffect(() => {
    let cancelled = false
    setLoading(true)
    setError(null)
    api
      .listSessions(limit, offset, { accountId, agentId, agentName, startedFrom, startedTo, transport })
      .then((res) => {
        if (cancelled) return
        setSessions(res.objects)
        setMeta(res.meta)
      })
      .catch((e) => {
        if (!cancelled) setError(e.message)
      })
      .finally(() => {
        if (!cancelled) setLoading(false)
      })
    return () => {
      cancelled = true
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [api, limit, offset, accountId, agentId, agentName, startedFrom, startedTo, transportKey, refetchTick])

  return { sessions, meta, loading, error, refetch }
}

// ---------------------------------------------------------------------------
// useSession — returns the current session from provider context
// ---------------------------------------------------------------------------

export function useSession() {
  const { session, sessionLoading, sessionError } = useObservabilityContext()
  return {
    session,
    loading: sessionLoading,
    error: sessionError,
  }
}

// ---------------------------------------------------------------------------
// useTimeline — derives timeline data from current session
// ---------------------------------------------------------------------------

export function useTimeline() {
  const { session, highlightedTurn, setHighlightedTurn } =
    useObservabilityContext()

  const metrics: SessionMetrics | null = session?.session_metrics ?? null
  const recordUrl: string | null = session?.record_url ?? null
  const sessionCreatedAt: string | undefined = session?.created_at

  return { metrics, recordUrl, sessionCreatedAt, highlightedTurn, setHighlightedTurn }
}

// ---------------------------------------------------------------------------
// useTranscript — derives transcript data from current session
// ---------------------------------------------------------------------------

export function useTranscript() {
  const { session, highlightedTurn, setHighlightedTurn } =
    useObservabilityContext()

  const metrics: SessionMetrics | null = session?.session_metrics ?? null
  const turns: TurnRecord[] = useMemo(
    () => metrics?.turns ?? [],
    [metrics],
  )
  const chatHistory: ChatItem[] | null = session?.chat_history ?? null

  return { turns, chatHistory, metrics, highlightedTurn, setHighlightedTurn }
}

// ---------------------------------------------------------------------------
// usePerformance — derives performance metrics from current session
// ---------------------------------------------------------------------------

export function usePerformance() {
  const { session } = useObservabilityContext()

  const metrics: SessionMetrics | null = session?.session_metrics ?? null
  const summary: MetricsSummary | null = metrics?.summary ?? null

  return { metrics, summary }
}

// ---------------------------------------------------------------------------
// useEvents / useOptions — raw session report slices
// ---------------------------------------------------------------------------

export function useEvents(): SessionEvent[] | null {
  const { session } = useObservabilityContext()
  const events = session?.events ?? null
  return useMemo(() => sortEventsByCreatedAt(events), [events])
}

export function useOptions(): Record<string, unknown> | null {
  const { session } = useObservabilityContext()
  return session?.options ?? null
}

export function useSessionEvaluations(): SessionExternalEvaluation[] {
  const { session } = useObservabilityContext()
  return session?.evaluations ?? []
}

export function useSessionTags(): SessionTag[] {
  const { session } = useObservabilityContext()
  return session?.tags ?? []
}

export function useSessionOutcome(): SessionOutcome | null {
  const { session } = useObservabilityContext()
  return session?.outcome ?? null
}

// ---------------------------------------------------------------------------
// useEvalRuns / useEvalRun / useEvalCase
// ---------------------------------------------------------------------------

export function useEvalRuns(
  limit = 20,
  initialOffset = 0,
  filters?: EvalsFilters,
) {
  const { api } = useObservabilityContext()
  const [runs, setRuns] = useState<EvalRunRow[]>([])
  const [meta, setMeta] = useState<PlivoMeta>({
    limit,
    offset: initialOffset,
    total_count: 0,
    next: null,
    previous: null,
  })
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)
  const [offset, setOffset] = useState(initialOffset)
  const [refetchTick, setRefetchTick] = useState(0)
  const refetch = useMemo(() => () => setRefetchTick((v) => v + 1), [])

  const { agentId, framework, testingFramework, accountId, startedFrom, startedTo } = filters ?? {}
  // Stable string keys for the array filters so effect deps don't churn
  // on new-but-equal-array identities every render.
  const frameworkKey = (framework ?? []).slice().sort().join(',')
  const testingFrameworkKey = (testingFramework ?? []).slice().sort().join(',')

  // Sync offset when the caller passes a live initialOffset (e.g. from URL
  // state). Callers who drive pagination via setOffset pass a stable 0 and
  // this no-ops after mount.
  useEffect(() => {
    setOffset(initialOffset)
  }, [initialOffset])

  useEffect(() => {
    setOffset(0)
  }, [agentId, frameworkKey, testingFrameworkKey, accountId, startedFrom, startedTo])

  useEffect(() => {
    let cancelled = false
    setLoading(true)
    setError(null)
    api
      .listEvalRuns(limit, offset, {
        agentId,
        framework: framework && framework.length ? framework : undefined,
        testingFramework:
          testingFramework && testingFramework.length ? testingFramework : undefined,
        accountId,
        startedFrom,
        startedTo,
      })
      .then((res) => {
        if (cancelled) return
        setRuns(res.objects)
        setMeta(res.meta)
      })
      .catch((e) => !cancelled && setError(e.message))
      .finally(() => !cancelled && setLoading(false))
    return () => { cancelled = true }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [api, limit, offset, agentId, frameworkKey, testingFrameworkKey, accountId, startedFrom, startedTo, refetchTick])

  // Live polling while any visible row is in-flight. Cleared as soon as
  // every row has finalized — keeps a finished page idle. 1500ms is fast
  // enough to feel live without pummelling the API; matches PR #45.
  const anyRunning = useMemo(
    () => runs.some((r) => r.status === 'running'),
    [runs],
  )
  useEffect(() => {
    if (!anyRunning) return
    const id = setInterval(() => setRefetchTick((v) => v + 1), 1500)
    return () => clearInterval(id)
  }, [anyRunning])

  return { runs, meta, loading, error, offset, setOffset, refetch }
}

export function useEvalRun(runId: string | undefined) {
  const { api } = useObservabilityContext()
  const [run, setRun] = useState<EvalRunDetail | null>(null)
  const [loading, setLoading] = useState(!!runId)
  const [error, setError] = useState<string | null>(null)
  const [refetchTick, setRefetchTick] = useState(0)
  const refetch = useMemo(() => () => setRefetchTick((v) => v + 1), [])

  useEffect(() => {
    if (!runId) return
    let cancelled = false
    setLoading(true)
    setError(null)
    api
      .getEvalRun(runId)
      .then((res) => !cancelled && setRun(res))
      .catch((e) => !cancelled && setError(e.message))
      .finally(() => !cancelled && setLoading(false))
    return () => { cancelled = true }
  }, [api, runId, refetchTick])

  // Live polling — when this run is still in flight, re-fetch every
  // 1.5s so streamed cases (S2.5 flusher) appear on the detail page
  // without a manual refresh. Same cadence as useEvalRuns. Effect
  // tears down the moment the status leaves 'running'.
  const isRunning = run?.status === 'running'
  useEffect(() => {
    if (!isRunning) return
    const id = setInterval(() => setRefetchTick((v) => v + 1), 1500)
    return () => clearInterval(id)
  }, [isRunning])

  return { run, loading, error, refetch }
}

export function useEvalCase(runId: string | undefined, caseId: string | undefined) {
  const { api } = useObservabilityContext()
  const [evalCase, setEvalCase] = useState<EvalCaseRow | null>(null)
  const [loading, setLoading] = useState(!!(runId && caseId))
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    if (!runId || !caseId) return
    let cancelled = false
    setLoading(true)
    setError(null)
    api
      .getEvalCase(runId, caseId)
      .then((res) => !cancelled && setEvalCase(res))
      .catch((e) => !cancelled && setError(e.message))
      .finally(() => !cancelled && setLoading(false))
    return () => { cancelled = true }
  }, [api, runId, caseId])

  return { evalCase, loading, error }
}

// ---------------------------------------------------------------------------
// useAgents — distinct agent_name rollup across sessions + eval_runs
// ---------------------------------------------------------------------------

export function useAgents(
  limit = 50,
  offset = 0,
  filters?: AgentsFilters,
) {
  const { api } = useObservabilityContext()
  const [agents, setAgents] = useState<AgentRow[]>([])
  const [meta, setMeta] = useState<PlivoMeta>({
    limit,
    offset,
    total_count: 0,
    next: null,
    previous: null,
  })
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)
  const [refetchTick, setRefetchTick] = useState(0)
  const refetch = useMemo(() => () => setRefetchTick((v) => v + 1), [])

  const accountId = filters?.accountId
  const agentId = filters?.agentId
  const agentName = filters?.agentName
  useEffect(() => {
    let cancelled = false
    setLoading(true)
    setError(null)
    api
      .listAgents(limit, offset, { accountId, agentId, agentName })
      .then((res) => {
        if (cancelled) return
        setAgents(res.objects)
        setMeta(res.meta)
      })
      .catch((e) => !cancelled && setError(e.message))
      .finally(() => !cancelled && setLoading(false))
    return () => { cancelled = true }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [api, limit, offset, accountId, agentId, agentName, refetchTick])

  return { agents, meta, loading, error, refetch }
}

export function useAgent(agentId: string | undefined, accountId?: string | null) {
  const { api } = useObservabilityContext()
  const [agent, setAgent] = useState<AgentRow | null>(null)
  const [loading, setLoading] = useState(!!agentId)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    if (!agentId) return
    let cancelled = false
    setLoading(true)
    setError(null)
    api
      .getAgent(agentId, accountId)
      .then((res) => !cancelled && setAgent(res))
      .catch((e) => !cancelled && setError(e.message))
      .finally(() => !cancelled && setLoading(false))
    return () => { cancelled = true }
  }, [api, agentId, accountId])

  return { agent, loading, error }
}

export function useAgentStats(
  agentId: string | undefined,
  range: AgentStatsRange = '24h',
  accountId?: string | null,
) {
  const { api } = useObservabilityContext()
  const [stats, setStats] = useState<AgentStats | null>(null)
  const [loading, setLoading] = useState(!!agentId)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    if (!agentId) return
    let cancelled = false
    setLoading(true)
    setError(null)
    api
      .getAgentStats(agentId, range, accountId)
      .then((res) => !cancelled && setStats(res))
      .catch((e) => !cancelled && setError(e.message))
      .finally(() => !cancelled && setLoading(false))
    return () => { cancelled = true }
  }, [api, agentId, range, accountId])

  return { stats, loading, error }
}

export function useConversationEvals(
  agentId: string | undefined,
  limit = 50,
  offset = 0,
  filters?: {
    accountId?: string | null
    sessionId?: string | null
    failedOnly?: boolean
  },
) {
  const { api } = useObservabilityContext()
  const [evals, setEvals] = useState<ConversationEvalSummary[]>([])
  const [meta, setMeta] = useState<PlivoMeta>({
    limit,
    offset,
    total_count: 0,
    next: null,
    previous: null,
  })
  const [loading, setLoading] = useState(!!agentId)
  const [error, setError] = useState<string | null>(null)

  const accountId = filters?.accountId ?? null
  const sessionId = filters?.sessionId ?? null
  const failedOnly = !!filters?.failedOnly

  useEffect(() => {
    if (!agentId) return
    let cancelled = false
    setLoading(true)
    setError(null)
    api
      .listConversationEvals(agentId, limit, offset, { accountId, sessionId, failedOnly })
      .then((res) => {
        if (cancelled) return
        setEvals(res.objects)
        setMeta(res.meta)
      })
      .catch((e) => !cancelled && setError(e.message))
      .finally(() => !cancelled && setLoading(false))
    return () => { cancelled = true }
  }, [api, agentId, limit, offset, accountId, sessionId, failedOnly])

  return { evals, meta, loading, error }
}

